INSERT INTO pac_categories (category, title, description, examples) VALUES ('PAC 1', 'Resuscitation and Critically-ill Cases', 'Patients are either in a state of cardiovascular collapse or in imminent danger of collapse. Require immediate medical attention.', 'heart attack, cardiac arrest, severe bleeding, shock, severe asthma attack');
INSERT INTO pac_categories (category, title, description, examples) VALUES ('PAC 2', 'Acutely-ill Cases (Non-Ambulant)', 'Patients are unable to move on their own and in various forms of severe distress. Stable cardiovascular state but require early attention to prevent deterioration.', 'stroke, long bone fractures, moderate-severe asthma');
INSERT INTO pac_categories (category, title, description, examples) VALUES ('PAC 3', 'Minor Emergencies (Ambulant)', 'Patients show acute symptoms but are still able to move on their own. Symptoms are mild to moderate; acute treatment will resolve symptoms.', 'bleeding cuts, moderate injuries, persistent high fever');
INSERT INTO pac_categories (category, title, description, examples) VALUES ('PAC 4', 'Non-Emergency', 'Non-emergency cases that do not require immediate medical attention. No present threat to life; symptoms can be managed in primary healthcare.', 'chronic lower back pain, high cholesterol, acne, mild cold');
